//! Cross-runtime fixture suite for `cryptfns::asn1`. The committed `.der`
//! bytes are the contract that the WASM and Flutter FFI builds also verify
//! against — see `web/tests/shares/asn1_fixtures.test.ts` and
//! `hoodik-app/integration_test/e2e/asn1_fixtures_test.dart`.
//!
//! Set `REGEN_FIXTURES=1` to overwrite the committed `.der` files from the
//! current encoder output, then commit the regenerated bytes.

mod fixtures;

use std::path::PathBuf;

use cryptfns::asn1::{
    encode_audit_event_sig_input_v1, encode_audit_event_v1, encode_entries_v1,
    encode_folder_member_list_v1, encode_member_sig_v1, encode_share_request_v1,
    AUDIT_EVENT_SIG_V1_PREFIX, AUDIT_EVENT_V1_PREFIX, FOLDER_LIST_V1_PREFIX, MEMBER_SIG_V1_PREFIX,
    SHARE_REQUEST_V1_PREFIX,
};
use cryptfns::hex;
use cryptfns::rsa;

fn fixtures_path(name: &str) -> PathBuf {
    let mut p = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    p.push("tests");
    p.push("fixtures");
    p.push(name);
    p
}

fn maybe_regen(name: &str, current: &[u8]) {
    if std::env::var("REGEN_FIXTURES").is_ok() {
        std::fs::write(fixtures_path(name), current).expect("writing regenerated fixture");
    }
}

#[test]
fn share_request_v1_matches_fixture() {
    let bytes = encode_share_request_v1(&fixtures::share_request_v1()).unwrap();
    maybe_regen("share_request_v1.der", &bytes);
    assert_eq!(
        bytes,
        fixtures::SHARE_REQUEST_DER,
        "share_request_v1 encoder drifted from committed fixture"
    );
}

